const items = $input.all();

return items.map(item => {
  const data = item.json;
  const firstName   = (data.first_name || 'there').trim();
  const email       = (data.email     || '').trim();
  const sessionId   = data.session_id;
  const contactId   = data.contact_id;
  const scheduledAt = new Date(data.scheduled_at);

  const dateStr = scheduledAt.toLocaleDateString('en-US', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    timeZone: 'America/New_York'
  });

  const bookingUrl = 'https://soul-synergy-hub.pages.dev/book';

  const html = [
    '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
    '<h2 style="color:#2D6A6A;margin-bottom:16px">\u2728 Thank You for Today\'s Session</h2>',
    '<p style="line-height:1.7;color:#333">Hi ' + firstName + ',</p>',
    '<p style="line-height:1.7;color:#333">Thank you so much for showing up for yourself today. It was a genuine pleasure spending this time with you, and I\'m inspired by your commitment to growth and clarity.</p>',
    '<p style="line-height:1.7;color:#333">As you reflect on our session from <strong>' + dateStr + '</strong>, I encourage you to:</p>',
    '<ul style="color:#333;line-height:2.0;padding-left:20px">',
    '<li>Revisit any insights or action items you noted during our conversation</li>',
    '<li>Be gentle with yourself as you put things into practice</li>',
    '<li>Notice the small shifts — they matter more than you think</li>',
    '</ul>',
    '<p style="line-height:1.7;color:#333">Whenever you feel ready to continue your journey, I\'d love to support you further.</p>',
    '<div style="text-align:center;margin:32px 0">',
    '<a href="' + bookingUrl + '" style="background:#2D6A6A;color:#fff;text-decoration:none;padding:14px 28px;border-radius:6px;font-size:15px;font-weight:600;display:inline-block">Book Your Next Session</a>',
    '</div>',
    '<p style="line-height:1.7;color:#333">With gratitude,<br><strong>Arushi Bhardwaj</strong><br>SoulSynergy Coaching</p>',
    '<hr style="border:none;border-top:1px solid #eee;margin:24px 0">',
    '<p style="color:#999;font-size:12px">SoulSynergy Coaching &mdash; Uncover. Align. Achieve.</p>',
    '</div>'
  ].join('');

  const resendPayload = JSON.stringify({
    from: 'SoulSynergy Coaching <onboarding@resend.dev>',
    to: [email],
    subject: '\u2728 Thank you for today\'s session, ' + firstName,
    html: html
  });

  return {
    json: {
      session_id:     sessionId,
      contact_id:     contactId,
      email:          email,
      resend_payload: resendPayload
    }
  };
});
